data.output:
200						ArmLabels:   armLabels,
201						Sandbox:     sandbox,
202						KeepSandbox: keepSandbox,
203						PostRun:     postRun,
204					}
205					record, err := agent.RunCompareWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
206					if err != nil {
207						return err
208					}
209					if asJSON {
210						enc := json.NewEncoder(cmd.OutOrStdout())
211						enc.SetIndent("", "  ")
212						return enc.Encode(record)
213					}
214					fmt.Fprintf(cmd.OutOrStdout(), "Comparison %s (%d arms)\n", record.ID, len(record.Arms))
215					for _, arm := range record.Arms {
216						status := "OK"
217						if arm.ExitCode != 0 {
218							status = fmt.Sprintf("FAIL (rc=%d)", arm.ExitCode)
219						}
220						cost := ""
221						if arm.CostUSD > 0 {
222							cost = fmt.Sprintf(" cost=$%.4f", arm.CostUSD)
223						}
224						fmt.Fprintf(cmd.OutOrStdout(), "  %-12s %s  tokens=%d  duration=%dms%s\n",
225							arm.Harness, status, arm.Tokens, arm.DurationMS, cost)
226						if arm.Diff != "" {
227							lines := strings.Count(arm.Diff, "\n")
228							fmt.Fprintf(cmd.OutOrStdout(), "             diff: %d lines\n", lines)
229						}
230					}
231					return nil
232				}
233	
234				// Quorum mode
235				if quorum != "" || harnesses != "" {
236					harnessNames := strings.Split(harnesses, ",")
237					if len(harnessNames) == 0 || (len(harnessNames) == 1 && harnessNames[0] == "") {
238						return fmt.Errorf("--harnesses required for quorum mode")
239					}
240					overrides := config.CLIOverrides{
241						Model:       model,
242						Effort:      effort,
243						Permissions: permissions,
244					}
245					if timeout > 0 {
246						overrides.Timeout = &timeout
247					}
248					rcfg, _ := config.LoadAndResolve(f.WorkingDir, overrides)
249					runtime := agent.QuorumRuntime{
250						AgentRunRuntime: agent.AgentRunRuntime{
251							Prompt:       prompt,
252							PromptFile:   promptFile,
253							PromptSource: promptSource,
254							WorkDir:      workDir,
255						},
256						Harnesses: harnessNames,
257						Strategy:  quorum,
258					}
259					results, err := agent.RunQuorumWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
260					if err != nil {
261						return err
262					}
263					met := agent.QuorumMet(quorum, 0, results)
264					if asJSON {
265						enc := json.NewEncoder(cmd.OutOrStdout())
266						enc.SetIndent("", "  ")
267						return enc.Encode(map[string]any{
268							"quorum_met": met,
269							"strategy":   quorum,
270							"results":    results,
271						})
272					}
273					for _, result := range results {
274						if result == nil {
275							continue
276						}
277						fmt.Fprintf(cmd.OutOrStdout(), "[%s] rc=%d tokens=%d duration=%dms\n",
278							result.Harness, result.ExitCode, result.Tokens, result.DurationMS)
279						if result.CondensedOutput != "" {
280							fmt.Fprintln(cmd.OutOrStdout(), result.CondensedOutput)
281						} else if result.Output != "" {
282							fmt.Fprintln(cmd.OutOrStdout(), result.Output)
283						}
284					}
285					if met {
286						fmt.Fprintf(cmd.OutOrStdout(), "Quorum: MET (%s)\n", quorum)
287					} else {
288						fmt.Fprintf(cmd.OutOrStdout(), "Quorum: NOT MET (%s)\n", quorum)
289						return fmt.Errorf("quorum not met")
290					}
291					return nil
292				}
293	
294				// Pass operator intent directly to Execute; do not pre-resolve
295				// the route. The upstream service owns harness+provider+model
296				// selection within the caller's passthrough constraints and
297				// MinPower/MaxPower bounds (CONTRACT-003 / ddx-da19756a).
298				profile = agent.NormalizeRoutingProfile(profile)
299	
300				overrides := config.CLIOverrides{
301					Harness:     harness,
302					Model:       model,
303					Profile:     profile,
304					Effort:      effort,
305					Permissions: permissions,
306				}
307				if timeout > 0 {
308					overrides.Timeout = &timeout
309				}
310				rcfg, _ := config.LoadAndResolve(f.WorkingDir, overrides)
311				if err := agent.ValidateEffortForRunViaService(cmd.Context(), f.WorkingDir, rcfg.Profile(), rcfg.Effort()); err != nil {
312					return err
313				}
314				runtime := agent.AgentRunRuntime{
315					Prompt:       prompt,
316					PromptFile:   promptFile,
317					PromptSource: promptSource,
318					WorkDir:      workDir,
319				}
320				result, err := agent.RunWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
321				if err != nil {
322					return err
323				}
324	
325				// Record the prompt→response pair for virtual harness replay.
326				if record, _ := cmd.Flags().GetBool("record"); record && result.ExitCode == 0 {
327					resolvedPrompt := prompt
328					if resolvedPrompt == "" && promptFile != "" {
329						data, _ := os.ReadFile(promptFile)
330						resolvedPrompt = string(data)
331					}
332					entry := &agent.VirtualEntry{
333						Prompt:       resolvedPrompt,
334						Response:     result.Output,
335						Harness:      result.Harness,
336						Model:        result.Model,
337						DelayMS:      result.DurationMS,
338						InputTokens:  result.InputTokens,
339						OutputTokens: result.OutputTokens,
340						CostUSD:      result.CostUSD,
341					}
342					dictDir := agent.VirtualDictionaryDir
343					// Load normalization patterns from config.
344					var patterns []config.NormalizePattern
345					if cfg, cfgErr := config.Load(); cfgErr == nil && cfg.Agent != nil && cfg.Agent.Virtual != nil {
346						patterns = cfg.Agent.Virtual.Normalize
347					}
348					if err := agent.RecordEntry(dictDir, entry, patterns...); err != nil {
349						fmt.Fprintf(os.Stderr, "Warning: failed to record response: %v\n", err)
350					} else {
351						normalized := agent.NormalizePrompt(resolvedPrompt, patterns)
352						fmt.Fprintf(os.Stderr, "Recorded response → %s/%s.json\n", dictDir, agent.PromptHash(normalized))
353					}
354				}
355	
356				// --json is a backward-compatible alias for --output json-result
357				if asJSON {
358					outputFmt = "json-result"
359				}
360				switch outputFmt {
361				case "json-result":
362					enc := json.NewEncoder(cmd.OutOrStdout())
363					enc.SetIndent("", "  ")
364					if err := enc.Encode(result); err != nil {
365						return err
366					}
367				case "session-jsonl":
368					if result.CondensedOutput != "" {
369						fmt.Fprint(cmd.OutOrStdout(), result.CondensedOutput)
370					} else if result.Output != "" {
371						fmt.Fprint(cmd.OutOrStdout(), result.Output)
372					}
373				case "text":
374					text := agent.ExtractOutput(result.Harness, result.Output)
375					if text != "" {
376						fmt.Fprint(cmd.OutOrStdout(), text)
377					}
378				default:
379					return fmt.Errorf("unknown --output value %q (valid: text, json-result, session-jsonl)", outputFmt)
380				}
381				if result.ExitCode != 0 {
382					msg := fmt.Sprintf("agent exited with code %d", result.ExitCode)
383					if result.Error != "" {
384						msg += "\n  error: " + result.Error
385					}
386					if result.Stderr != "" && result.Stderr != result.Error {
387						// Show at most 5 stderr lines to surface auth/rate-limit diagnostics
388						// without flooding the terminal with full agent output.
389						lines := strings.SplitN(strings.TrimSpace(result.Stderr), "\n", 6)
390						if len(lines) > 5 {
391							lines = append(lines[:5], "  ...")
392						}
393						msg += "\n  stderr:\n    " + strings.Join(lines, "\n    ")
394					}
395					return fmt.Errorf("%s", msg)
396				}
397				return nil
398			},
399		}

399		}
