236	// checkForUpdates performs automatic update check (synchronous, once per 24h)
237	func (f *CommandFactory) checkForUpdates(cmd *cobra.Command) {
238		// Check if disabled via env var
239		if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
240			return
241		}
242	
243		// Load config
244		cfg, err := config.Load()
245		if err != nil {
246			// Silent failure - use defaults
247			cfg = config.DefaultNewConfig()
248		}
249	
250		// Check if disabled via config
251		if cfg.UpdateCheck != nil && !cfg.UpdateCheck.Enabled {
252			return
253		}
254	
255		// Create checker and perform check (synchronous)
256		checker := update.NewChecker(f.Version, cfg)
257		f.updateMu.Lock()
258		f.updateChecker = checker
259		f.updateDone = make(chan struct{})
260		done := f.updateDone
261		f.updateMu.Unlock()
262	
263		// Run the check asynchronously so command startup is never blocked.
264		go func() {
265			defer close(done)
266			_, _ = checker.CheckForUpdate(context.Background())
267			// Also refresh plugin version cache while we have a network call in flight.
268			f.refreshPluginVersionCache()
269		}()
270	}
