272	// displayUpdateNotification shows update notification if available
273	func (f *CommandFactory) displayUpdateNotification(cmd *cobra.Command) error {
274		// Skip if disabled via environment variable
275		if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
276			return nil
277		}
278	
279		f.updateMu.Lock()
280		checker := f.updateChecker
281		done := f.updateDone
282		f.updateMu.Unlock()
283	
284		if checker == nil {
285			return nil
286		}
287	
288		if done != nil {
289			select {
290			case <-done:
291			default:
292				return nil
293			}
294		}
295	
296		// Skip update notification for help commands
297		if cmd.Name() == "help" || cmd.Parent() != nil && cmd.Parent().Name() == "help" {
298			return nil
299		}
300	
301		// Skip update notification for machine-readable output formats
302		jsonFlag, _ := cmd.Flags().GetBool("json")
303		if jsonFlag {
304			return nil
305		}
306	
307		// Skip update notification if silent flag is set
308		silentFlag, _ := cmd.Flags().GetBool("silent")
309		if silentFlag {
310			return nil
311		}
312	
313		// Skip update notification if --no-check flag is set (for version command)
314		noCheck, _ := cmd.Flags().GetBool("no-check")
315		if noCheck {
316			return nil
317		}
318	
319		// Skip when stdout is not a terminal (pipes, scripts, CI)
320		if !isatty.IsTerminal(os.Stdout.Fd()) && !isatty.IsCygwinTerminal(os.Stdout.Fd()) {
321			return nil
322		}
323	
324		available, version, err := checker.IsUpdateAvailable()
325		if err != nil || !available {
326			if err != nil {
327				_, _ = fmt.Fprintf(os.Stderr, "Warning: Could not check for updates: %v\n", err)
328			}
329			return nil
330		}
331	
332		// Show update notification with changelog for version command
333		// Always write to stderr so it doesn't corrupt JSON pipelines
334		isVersionCmd := cmd.Use == "version"
335		if isVersionCmd {
336			_, _ = fmt.Fprintf(os.Stderr,
337				"\n⬆️  Update available: %s (run 'ddx upgrade' to install)\n\nWhat's new:\n  • Performance improvements\n  • Bug fixes\n  • New features\n",
338				version)
339		} else {
340			_, _ = fmt.Fprintf(os.Stderr,
