325				// Record the prompt→response pair for virtual harness replay.
326				if record, _ := cmd.Flags().GetBool("record"); record && result.ExitCode == 0 {
327					resolvedPrompt := prompt
328					if resolvedPrompt == "" && promptFile != "" {
329						data, _ := os.ReadFile(promptFile)
330						resolvedPrompt = string(data)
331					}
332					entry := &agent.VirtualEntry{
333						Prompt:       resolvedPrompt,
334						Response:     result.Output,
335						Harness:      result.Harness,
336						Model:        result.Model,
337						DelayMS:      result.DurationMS,
338						InputTokens:  result.InputTokens,
339						OutputTokens: result.OutputTokens,
340						CostUSD:      result.CostUSD,
341					}
342					dictDir := agent.VirtualDictionaryDir
343					// Load normalization patterns from config.
344					var patterns []config.NormalizePattern
345					if cfg, cfgErr := config.Load(); cfgErr == nil && cfg.Agent != nil && cfg.Agent.Virtual != nil {
346						patterns = cfg.Agent.Virtual.Normalize
347					}
348					if err := agent.RecordEntry(dictDir, entry, patterns...); err != nil {
349						fmt.Fprintf(os.Stderr, "Warning: failed to record response: %v\n", err)
350					} else {
351						normalized := agent.NormalizePrompt(resolvedPrompt, patterns)
352						fmt.Fprintf(os.Stderr, "Recorded response → %s/%s.json\n", dictDir, agent.PromptHash(normalized))
353					}
354				}
355	
356				// --json is a backward-compatible alias for --output json-result
357				if asJSON {
358					outputFmt = "json-result"
359				}
360				switch outputFmt {
361				case "json-result":
362					enc := json.NewEncoder(cmd.OutOrStdout())
363					enc.SetIndent("", "  ")
364					if err := enc.Encode(result); err != nil {
365						return err
366					}
367				case "session-jsonl":
368					if result.CondensedOutput != "" {
369						fmt.Fprint(cmd.OutOrStdout(), result.CondensedOutput)
370					} else if result.Output != "" {
371						fmt.Fprint(cmd.OutOrStdout(), result.Output)
372					}
373				case "text":
374					text := agent.ExtractOutput(result.Harness, result.Output)
375					if text != "" {
376						fmt.Fprint(cmd.OutOrStdout(), text)
377					}
378				default:
379					return fmt.Errorf("unknown --output value %q (valid: text, json-result, session-jsonl)", outputFmt)
380				}
381				if result.ExitCode != 0 {
382					msg := fmt.Sprintf("agent exited with code %d", result.ExitCode)
383					if result.Error != "" {
384						msg += "\n  error: " + result.Error
385					}
386					if result.Stderr != "" && result.Stderr != result.Error {
387						// Show at most 5 stderr lines to surface auth/rate-limit diagnostics
388						// without flooding the terminal with full agent output.
389						lines := strings.SplitN(strings.TrimSpace(result.Stderr), "\n", 6)
390						if len(lines) > 5 {
391							lines = append(lines[:5], "  ...")
392						}
393						msg += "\n  stderr:\n    " + strings.Join(lines, "\n    ")
394					}
395					return fmt.Errorf("%s", msg)
396				}
397				return nil
398			},
399		}

