291	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
292	// querying the service's ListHarnesses and (best-effort) the harness registry.
293	// It is the production replacement for Runner.Capabilities.
294	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
295		if ctx == nil {
296			ctx = context.Background()
297		}
298		svc, err := NewServiceFromWorkDir(workDir)
299		if err != nil {
300			return nil, fmt.Errorf("agent: build service: %w", err)
301		}
302		infos, err := svc.ListHarnesses(ctx)
303		if err != nil {
304			return nil, fmt.Errorf("agent: list harnesses: %w", err)
305		}
306		var info *agentlib.HarnessInfo
307		for i := range infos {
308			if infos[i].Name == harnessName {
309				info = &infos[i]
310				break
311			}
312		}
313		if info == nil {
314			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
315		}
316	
317		// Pull binary and reasoning-level metadata from the local registry — the
318		// service does not expose these directly today.
319		registry := newHarnessRegistry()
320		harness, _ := registry.Get(harnessName)
321	
322		caps := &HarnessCapabilities{
323			Harness:             info.Name,
324			Available:           info.Available,
325			Binary:              harness.Binary,
326			Path:                info.Path,
327			Surface:             harness.Surface,
328			CostClass:           info.CostClass,
329			IsLocal:             info.IsLocal,
330			ExactPinSupport:     info.ExactPinSupport,
331			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
332			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
333		}
334		if len(info.SupportedReasoning) > 0 {
335			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
336		} else if len(harness.ReasoningLevels) > 0 {
337			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
338		}
339	
340		if harness.DefaultModel != "" {
341			caps.Model = harness.DefaultModel
342			caps.Models = []string{harness.DefaultModel}
343		}
344	
345		return caps, nil
346	}
