351	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
352		status := ProviderStatus{Reachable: false}
353		if ctx == nil {
354			ctx = context.Background()
355		}
356		if harnessName == "virtual" || harnessName == "agent" {
357			status.Reachable = true
358			status.CreditsOK = true
359			return status
360		}
361		svc, err := NewServiceFromWorkDir(workDir)
362		if err != nil {
363			status.Error = err.Error()
364			return status
365		}
366		if timeout > 0 {
367			var cancel context.CancelFunc
368			ctx, cancel = context.WithTimeout(ctx, timeout)
369			defer cancel()
370		}
371		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
372			errStr := strings.ToLower(err.Error())
373			status.Error = err.Error()
374			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
375				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
376				status.CreditsOK = false
377			}
378			return status
379		}
380		status.Reachable = true
381		status.CreditsOK = true
382		return status
383	}
