385	// ValidateForExecuteLoopViaService is the production replacement for
386	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
387	// will pick at claim time). When harness is specified it confirms the harness
388	// exists in the service registry and (when model is set) attempts a
389	// ResolveRoute pre-flight.
390	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
391		if harnessName == "" {
392			return nil
393		}
394		if ctx == nil {
395			ctx = context.Background()
396		}
397		svc, err := NewServiceFromWorkDir(workDir)
398		if err != nil {
399			return fmt.Errorf("agent: build service: %w", err)
400		}
401		infos, err := svc.ListHarnesses(ctx)
402		if err != nil {
403			return fmt.Errorf("agent: list harnesses: %w", err)
404		}
405		found := false
406		for _, info := range infos {
407			if info.Name == harnessName {
408				found = true
409				if !info.Available {
410					return fmt.Errorf("agent: harness %s not available", harnessName)
411				}
412				break
413			}
414		}
415		if !found {
416			return fmt.Errorf("agent: unknown harness: %s", harnessName)
417		}
418	
419		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
420		// model is provided and provider/model-ref are not set.
421		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
422			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
423				Model:    model,
424				Harness:  harnessName,
425				ModelRef: modelRef,
426				Provider: provider,
427			}); err != nil {
428				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
429			}
430		}
431		return nil
432	}
