434	// ValidateEffortForRunViaService rejects effort requests that no currently
435	// available harness can satisfy. `ddx agent run` passes effort through to the
436	// service rather than resolving a route locally, but the command still needs a
437	// fast failure for obviously impossible combinations so operators get a useful
438	// error instead of a silent success path.
439	func ValidateEffortForRunViaService(ctx context.Context, workDir, profile, effort string) error {
440		if effort == "" {
441			return nil
442		}
443		if ctx == nil {
444			ctx = context.Background()
445		}
446		svc, err := NewServiceFromWorkDir(workDir)
447		if err != nil {
448			return fmt.Errorf("agent: build service: %w", err)
449		}
450		infos, err := svc.ListHarnesses(ctx)
451		if err != nil {
452			return fmt.Errorf("agent: list harnesses: %w", err)
453		}
454		registry := newHarnessRegistry()
455		for _, info := range infos {
456			if !info.Available {
457				continue
458			}
459			if harness, ok := registry.Get(info.Name); ok && harness.EffortFlag != "" {
460				return nil
461			}
462		}
463		if profile == "" {
464			return fmt.Errorf("agent: no selected provider candidate satisfies effort %q", effort)
465		}
466		return fmt.Errorf("agent: no selected provider candidate satisfies profile %q and effort %q", profile, effort)
467	}
